-- Seed 24 advisors from War Desk V6 prototype
-- Using uuid_generate_v5 with DNS namespace for deterministic UUIDs from original numeric IDs


-- Seed default availability for all advisors (Mon-Fri 9am-5pm ET)
select a.id, dow.d, '09:00'::time, '17:00'::time, 'America/New_York'
from public.advisors a
cross join (values (1),(2),(3),(4),(5)) as dow(d);
